import React from 'react';
import { Outlet, Link, Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const Icons = {
  Home: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>,
  Task: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>,
  Check: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
  Facility: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
};

const StaffLayout = () => {
  const { user, logout } = useAuth();
  const { staffList } = useData();
  const location = useLocation();

  if (!user) return <Navigate to="/" />;

  const currentUserInfo = staffList.find(s => s.id === user.id) || user;
  const isActive = (path) => location.pathname === path;

  // Style cho Bottom Nav Items
  const navItemStyle = (path) => ({ 
    display: 'flex', flexDirection: 'column', alignItems: 'center', 
    textDecoration: 'none', color: isActive(path) ? '#003366' : '#999',
    flex: 1
  });

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#f0f2f5' }}>
      
      {/* HEADER: Identical to Admin (White BG, Fixed) */}
      <header style={{ 
          background: '#ffffff', 
          color: '#003366', 
          padding: '0 20px', 
          height: '65px', 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          boxShadow: '0 2px 4px rgba(0,0,0,0.08)', 
          position: 'sticky', 
          top: 0, 
          zIndex: 1000 
      }}>
         <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <img src="/BA LOGO.png" alt="Be Able VN Logo" style={{ height: '45px', objectFit: 'contain' }} />
            <div>
                <h1 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 'bold' }}>Be Able VN</h1>
                <span style={{ fontSize: '0.75rem', color: '#666' }}>Staff Portal</span>
            </div>
         </div>
         <button onClick={logout} style={{ border: '1px solid #003366', background: 'transparent', color: '#003366', padding: '6px 15px', borderRadius: '4px', cursor: 'pointer', fontWeight: '500' }}>Đăng xuất</button>
      </header>

      {/* Main Content */}
      <main style={{ flex: 1, padding: '15px', paddingBottom: '80px' }}>
        
        {/* INFO CARD: User Info & UBI (Đặt dưới Header để Header sạch sẽ) */}
        <div style={{ background: 'white', padding: '15px', borderRadius: '8px', marginBottom: '15px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                    <strong style={{ fontSize: '1.1rem', color: '#003366' }}>{currentUserInfo.name}</strong>
                    <div style={{ display: 'flex', gap: '5px', marginTop: '5px', flexWrap: 'wrap' }}>
                        {currentUserInfo.positions && currentUserInfo.positions.length > 0 ? (
                            currentUserInfo.positions.map(p => (
                                <span key={p} style={{ background: '#e6f7ff', color: '#003366', padding: '2px 8px', borderRadius: '4px', fontSize: '0.75rem', fontWeight: 'bold' }}>{p}</span>
                            ))
                        ) : <span style={{fontSize: '0.75rem', color: '#888'}}>Staff</span>}
                    </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: '0.7rem', color: '#666', textTransform: 'uppercase' }}>UBI ({currentUserInfo.ubiPercentage || 100}%)</div>
                    <strong style={{ color: '#28a745', fontSize: '1.1rem' }}>
                        {((currentUserInfo.baseUBI || 0) * (currentUserInfo.ubiPercentage || 100) / 100).toLocaleString()} đ
                    </strong>
                </div>
            </div>
        </div>

        {/* Nội dung trang con (Check-in/Out, Facility, Tasks...) */}
        <Outlet />
      </main>

      {/* Bottom Navigation for Mobile */}
      <nav style={{ 
        position: 'fixed', bottom: 0, left: 0, right: 0, background: 'white', 
        borderTop: '1px solid #ddd', display: 'flex', justifyContent: 'space-around', padding: '10px 0',
        zIndex: 1000, boxShadow: '0 -2px 10px rgba(0,0,0,0.05)'
      }}>
        <Link to="/staff/my-tasks" style={navItemStyle('/staff/my-tasks')}>
            <Icons.Task active={isActive('/staff/my-tasks')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>Nhiệm vụ</span>
        </Link>
        <Link to="/staff/attendance" style={navItemStyle('/staff/attendance')}>
            <Icons.Check active={isActive('/staff/attendance')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>Chấm công</span>
        </Link>
        <Link to="/staff/facility-check" style={navItemStyle('/staff/facility-check')}>
            <Icons.Facility active={isActive('/staff/facility-check')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>CSVC</span>
        </Link>
        <Link to="/staff/performance" style={navItemStyle('/staff/performance')}>
            <Icons.Home active={isActive('/staff/performance')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>Hiệu suất</span>
        </Link>
      </nav>
    </div>
  );
};

export default StaffLayout;
